import{_ as a,o as t,c as r,a2 as o}from"./chunks/framework.BFZItJIV.js";const m=JSON.parse('{"title":"Roadmap","description":"Planned and in-progress features for TalaDB — ordered by impact and priority.","frontmatter":{"title":"Roadmap","description":"Planned and in-progress features for TalaDB — ordered by impact and priority."},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),i={name:"roadmap.md"};function n(s,e,d,c,l,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>This page tracks planned and in-progress work for TalaDB. Sections and items are ordered by estimated impact — things at the top affect the most users and unblock the most use cases.</p><p>Have an idea or want to help prioritise? Open a <a href="https://github.com/thinkgrid-labs/taladb/discussions" target="_blank" rel="noreferrer">GitHub Discussion</a> or a feature request issue.</p><hr><h2 id="_1-·-developer-experience" tabindex="-1">1 · Developer experience <a class="header-anchor" href="#_1-·-developer-experience" aria-label="Permalink to &quot;1 · Developer experience&quot;">​</a></h2><p>Better DX drives adoption and reduces time-to-production.</p><h3 id="sync" tabindex="-1">Sync <a class="header-anchor" href="#sync" aria-label="Permalink to &quot;Sync&quot;">​</a></h3><p><strong>Future extensions</strong> of this feature (not in scope for initial release):</p><ul><li>Native NoSQL adapters (<code>sync.adapter: mongodb | firestore | dynamodb</code>) with direct connection strings, removing the need for an intermediate API</li><li>Bi-directional pull: <code>taladb sync --pull</code> fetches from the remote and merges locally</li><li>Per-collection sync config (sync some collections, skip others)</li></ul><h3 id="taladb-generate-—-typescript-type-generation" tabindex="-1"><code>taladb generate</code> — TypeScript type generation <a class="header-anchor" href="#taladb-generate-—-typescript-type-generation" aria-label="Permalink to &quot;`taladb generate` — TypeScript type generation&quot;">​</a></h3><p>Inspect a live database and emit TypeScript interfaces for each collection, inferred from the stored documents. Useful for projects that don&#39;t start with a schema.</p><h3 id="vs-code-extension" tabindex="-1">VS Code extension <a class="header-anchor" href="#vs-code-extension" aria-label="Permalink to &quot;VS Code extension&quot;">​</a></h3><p>Syntax highlighting for TalaDB filter expressions in JSON, inline document previews, and a collection browser panel in the VS Code sidebar.</p><hr><h2 id="_2-·-advanced-sync" tabindex="-1">2 · Advanced sync <a class="header-anchor" href="#_2-·-advanced-sync" aria-label="Permalink to &quot;2 · Advanced sync&quot;">​</a></h2><h3 id="sync-over-websockets" tabindex="-1">Sync over WebSockets <a class="header-anchor" href="#sync-over-websockets" aria-label="Permalink to &quot;Sync over WebSockets&quot;">​</a></h3><p>A reference sync server (<code>taladb-sync-server</code>) that accepts snapshot diffs over a WebSocket connection and applies <code>LastWriteWins</code> or CRDT merge logic server-side, enabling multi-device sync without a cloud database.</p><hr><h2 id="_3-·-storage" tabindex="-1">3 · Storage <a class="header-anchor" href="#_3-·-storage" aria-label="Permalink to &quot;3 · Storage&quot;">​</a></h2><p>Internal improvements that improve efficiency and interoperability.</p><h3 id="pluggable-serialisation" tabindex="-1">Pluggable serialisation <a class="header-anchor" href="#pluggable-serialisation" aria-label="Permalink to &quot;Pluggable serialisation&quot;">​</a></h3><p>Allow the caller to swap <code>postcard</code> for <code>MessagePack</code> or <code>CBOR</code> via a <code>Codec</code> trait, making it easier to interoperate with databases or wire formats that already use those encodings.</p><hr><h2 id="_4-·-platform" tabindex="-1">4 · Platform <a class="header-anchor" href="#_4-·-platform" aria-label="Permalink to &quot;4 · Platform&quot;">​</a></h2><p>Expanding the runtimes TalaDB can target.</p><h3 id="swift-kotlin-native-packages" tabindex="-1">Swift / Kotlin native packages <a class="header-anchor" href="#swift-kotlin-native-packages" aria-label="Permalink to &quot;Swift / Kotlin native packages&quot;">​</a></h3><p>First-party Swift (<code>TalaDB.swift</code>) and Kotlin (<code>taladb-kotlin</code>) packages that wrap the C FFI layer directly, without React Native, for native iOS and Android apps that want an embedded document store.</p><h3 id="wasi-target" tabindex="-1">WASI target <a class="header-anchor" href="#wasi-target" aria-label="Permalink to &quot;WASI target&quot;">​</a></h3><p>Compile <code>taladb-core</code> to WASI (<code>wasm32-wasip1</code>) so it can run inside WASI runtimes (Wasmtime, WasmEdge, Fastly Compute) with filesystem access — bringing the same engine to server-side WASM environments.</p>',29)])])}const u=a(i,[["render",n]]);export{m as __pageData,u as default};
